/**
 * User notification preferences model.
 *
 * Supports per-channel preferences for email, SMS, and webhook channels.
 * Each channel has an independent enabled flag and category subscriptions.
 *
 * DECISION CHANGE (Agent 9): The original model (Agent 3) assumed email-only.
 * With SMS added (Agent 8) and webhook already present, this model now supports
 * per-channel preferences. The `email` field is preserved for backward
 * compatibility; `sms` and `webhook` fields have been added alongside it.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/**
 * Base channel preferences shared by all notification channels.
 * Each channel has an enabled switch and per-category subscriptions.
 */
export interface ChannelPreferences {
  /** Master switch — when false, no notifications are sent on this channel. */
  enabled: boolean;
  /** Notification types the user wants to receive on this channel. */
  subscribedCategories: NotificationType[];
}

/**
 * How frequently email notifications are delivered.
 * - 'immediate': sent as events occur
 * - 'daily': batched into a daily digest
 * - 'weekly': batched into a weekly digest
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Email-specific notification preferences.
 * Extends ChannelPreferences with email-specific frequency setting.
 */
export interface EmailPreferences extends ChannelPreferences {
  /** Delivery frequency for non-critical emails. */
  frequency: EmailFrequency;
}

/**
 * SMS-specific notification preferences.
 */
export type SmsPreferences = ChannelPreferences;

/**
 * Webhook-specific notification preferences.
 */
export type WebhookPreferences = ChannelPreferences;

/**
 * A stored user preferences record.
 *
 * Each channel has its own preferences block. Channels can be independently
 * enabled/disabled and have independent category subscriptions.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms: SmsPreferences;
  webhook: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields are optional —
 * only provided fields are changed.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating channel preferences (SMS, webhook).
 * All fields are optional — only provided fields are changed.
 */
export interface UpdateChannelPreferencesInput {
  enabled?: boolean;
  subscribedCategories?: NotificationType[];
}

/** All notification categories. */
const ALL_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_updated',
];

/**
 * Default email preferences for new users — all notifications enabled, immediate delivery.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [...ALL_CATEGORIES],
};

/**
 * Default SMS preferences for new users — disabled by default (opt-in).
 */
export const DEFAULT_SMS_PREFERENCES: SmsPreferences = {
  enabled: false,
  subscribedCategories: [...ALL_CATEGORIES],
};

/**
 * Default webhook preferences for new users — disabled by default (opt-in).
 */
export const DEFAULT_WEBHOOK_PREFERENCES: WebhookPreferences = {
  enabled: false,
  subscribedCategories: [...ALL_CATEGORIES],
};

/**
 * Maps a NotificationChannel to the corresponding field key on UserPreferences.
 * Only channels that have user-configurable preferences are included.
 */
export const CHANNEL_PREFERENCE_KEY: Record<
  Extract<NotificationChannel, 'email' | 'sms' | 'webhook'>,
  keyof Pick<UserPreferences, 'email' | 'sms' | 'webhook'>
> = {
  email: 'email',
  sms: 'sms',
  webhook: 'webhook',
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: JSON.parse(record['email'] as string),
      sms: JSON.parse(record['sms'] as string),
      webhook: JSON.parse(record['webhook'] as string),
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      sms: JSON.stringify(entity.sms),
      webhook: JSON.stringify(entity.webhook),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences for a specific user.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for user notification preferences.
 *
 * Supports per-channel preferences for email, SMS, and webhook.
 * The NotificationService consults this service before dispatching notifications
 * on any channel.
 *
 * DECISION CHANGE (Agent 9): Originally email-only (Agent 3). Now supports
 * multi-channel preferences with a generic `shouldSend(channel)` method.
 * The email-specific methods are preserved for backward compatibility.
 */

import type { NotificationType, NotificationChannel } from '../models/notification.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
  UpdateChannelPreferencesInput,
  ChannelPreferences,
} from '../models/user-preferences.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset ID counter — for testing only. */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if no preferences exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating default preferences if none exist.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    this.logger.info(`Creating default preferences for user: ${userId}`);
    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedCategories: [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories] },
      sms: { ...DEFAULT_SMS_PREFERENCES, subscribedCategories: [...DEFAULT_SMS_PREFERENCES.subscribedCategories] },
      webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedCategories: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories] },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(preferences);
    return preferences;
  }

  /**
   * Update email preferences for a user. Creates default preferences first
   * if none exist.
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateEmailPreferencesInput,
  ): UserPreferences {
    this.logger.info(`Updating email preferences for user: ${userId}`);

    const current = this.getOrCreatePreferences(userId);
    const updatedEmail = {
      enabled: input.enabled ?? current.email.enabled,
      frequency: input.frequency ?? current.email.frequency,
      subscribedCategories:
        input.subscribedCategories ?? current.email.subscribedCategories,
    };

    const updated = this.preferencesRepository.update(current.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });

    return updated;
  }

  /**
   * Update SMS preferences for a user. Creates default preferences first
   * if none exist.
   */
  updateSmsPreferences(
    userId: string,
    input: UpdateChannelPreferencesInput,
  ): UserPreferences {
    this.logger.info(`Updating SMS preferences for user: ${userId}`);

    const current = this.getOrCreatePreferences(userId);
    const updatedSms: ChannelPreferences = {
      enabled: input.enabled ?? current.sms.enabled,
      subscribedCategories:
        input.subscribedCategories ?? current.sms.subscribedCategories,
    };

    const updated = this.preferencesRepository.update(current.id, {
      sms: updatedSms,
      updatedAt: new Date(),
    });

    return updated;
  }

  /**
   * Update webhook preferences for a user. Creates default preferences first
   * if none exist.
   */
  updateWebhookPreferences(
    userId: string,
    input: UpdateChannelPreferencesInput,
  ): UserPreferences {
    this.logger.info(`Updating webhook preferences for user: ${userId}`);

    const current = this.getOrCreatePreferences(userId);
    const updatedWebhook: ChannelPreferences = {
      enabled: input.enabled ?? current.webhook.enabled,
      subscribedCategories:
        input.subscribedCategories ?? current.webhook.subscribedCategories,
    };

    const updated = this.preferencesRepository.update(current.id, {
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });

    return updated;
  }

  /**
   * Generic check: should a notification be sent to a user on the given channel?
   *
   * Returns true if:
   * - The user has no preferences (defaults allow email, but not SMS/webhook)
   * - The channel is enabled AND the notification type is subscribed
   *
   * For channels without configurable preferences (e.g. in_app), returns true.
   */
  shouldSend(
    userId: string,
    channel: NotificationChannel,
    notificationType: NotificationType,
  ): boolean {
    // Channels without configurable preferences always allow
    if (channel === 'in_app') {
      return true;
    }

    const preferences = this.preferencesRepository.findByUserId(userId);

    // No preferences stored — use defaults:
    // email is enabled by default, SMS and webhook are disabled by default
    if (!preferences) {
      if (channel === 'email') {
        return true;
      }
      // SMS and webhook are opt-in — disabled by default
      return false;
    }

    const channelPrefs = this.getChannelPreferences(preferences, channel);
    if (!channelPrefs) {
      return true;
    }

    if (!channelPrefs.enabled) {
      return false;
    }

    return channelPrefs.subscribedCategories.includes(notificationType);
  }

  /**
   * Check whether a notification should be sent to a user based on their
   * email preferences.
   *
   * Backward-compatible wrapper around shouldSend().
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSend(userId, 'email', notificationType);
  }

  /**
   * Get channel-specific preferences from a UserPreferences record.
   */
  private getChannelPreferences(
    preferences: UserPreferences,
    channel: NotificationChannel,
  ): ChannelPreferences | undefined {
    switch (channel) {
      case 'email':
        return preferences.email;
      case 'sms':
        return preferences.sms;
      case 'webhook':
        return preferences.webhook;
      default:
        return undefined;
    }
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * ARCHITECTURE: Event-driven via EventBus (unified pattern).
 *
 * All notification triggers arrive through EventBus subscriptions. The service
 * translates domain events into NotificationPayloads and dispatches them through
 * registered NotificationAdapters based on the payload's channel.
 *
 * Multi-channel support: When adapters are registered for multiple channels,
 * the service dispatches to each channel independently, checking per-channel
 * user preferences before sending.
 *
 * CONSTRAINTS:
 * - All notifications must flow through EventBus.emit() — no direct calls.
 * - All delivery channels must have a registered NotificationAdapter.
 * - Adapters are registered via registerAdapter() and dispatched by channel.
 * - The service emits notification:sent and notification:failed events for
 *   observability (other services can subscribe to track delivery).
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events and emitting notification events
 * - NotificationAdapter implementations for delivery
 * - PreferencesService (optional) for per-channel user preference checks
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type {
  Notification,
  NotificationAdapter,
  NotificationChannel,
  NotificationPayload,
  NotificationType,
} from '../models/notification.js';
import type { PreferencesService } from './preferences.service.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset ID counter — for testing only. */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private preferencesService: PreferencesService | null = null;

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Set the preferences service used to check user notification preferences
   * before dispatching. When set, notifications are suppressed if the user
   * has opted out of the notification type or disabled the channel entirely.
   */
  setPreferencesService(preferencesService: PreferencesService): void {
    this.preferencesService = preferencesService;
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is supported; registering a second
   * adapter for the same channel replaces the previous one.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Register event handlers for notification triggers.
   * All handlers subscribe via EventBus — no other event mechanism is used.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user on all registered channels.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    const basePayload = {
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      notificationType: 'order_confirmation' as NotificationType,
      priority: 'normal' as const,
      metadata: { orderId: event.order.id, userId: event.user.id },
    };

    this.dispatchToChannels(event.user.id, event.user.email, basePayload);
  }

  /**
   * Handle order status change — notify user of update on all registered channels.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const basePayload = {
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      notificationType: 'order_status_update' as NotificationType,
      priority: 'normal' as const,
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    };

    this.dispatchToChannels(event.order.userId, event.order.userId, basePayload);
  }

  /**
   * Dispatch a notification to all registered channels, checking per-channel
   * preferences for each.
   */
  private dispatchToChannels(
    userId: string,
    recipient: string,
    basePayload: Omit<NotificationPayload, 'recipient' | 'channel'>,
  ): void {
    const channels = this.getRegisteredChannels();

    // If no adapters are registered, dispatch to email (stored as pending)
    if (channels.length === 0) {
      if (this.isChannelAllowed(userId, 'email', basePayload.notificationType)) {
        this.dispatchNotification({
          ...basePayload,
          recipient,
          channel: 'email',
        });
      } else {
        this.logger.info(`Email suppressed for user ${userId}: ${basePayload.notificationType}`);
      }
      return;
    }

    for (const channel of channels) {
      if (!this.isChannelAllowed(userId, channel, basePayload.notificationType)) {
        this.logger.info(`${channel} suppressed for user ${userId}: ${basePayload.notificationType}`);
        continue;
      }

      this.dispatchNotification({
        ...basePayload,
        recipient,
        channel,
      });
    }
  }

  /**
   * Get channels that have registered adapters.
   */
  private getRegisteredChannels(): NotificationChannel[] {
    return Array.from(this.adapters.keys());
  }

  /**
   * Check whether a notification is allowed for a user on the given channel
   * based on their preferences. Returns true if no preferences service is
   * configured (backwards compatible) or if the user's preferences allow it.
   */
  private isChannelAllowed(
    userId: string,
    channel: NotificationChannel,
    notificationType: NotificationType,
  ): boolean {
    if (!this.preferencesService) {
      return true;
    }
    return this.preferencesService.shouldSend(userId, channel, notificationType);
  }

  /**
   * Dispatch a notification through the appropriate adapter.
   *
   * Creates a Notification record, attempts delivery via the registered adapter
   * for the payload's channel, and emits a notification:sent or notification:failed
   * event for observability.
   *
   * If no adapter is registered for the channel, the notification is stored
   * with 'pending' status (allows in-app retrieval without a delivery adapter).
   */
  private dispatchNotification(payload: NotificationPayload): void {
    const notification: Notification = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      notificationType: payload.notificationType,
      channel: payload.channel,
      priority: payload.priority,
      status: 'pending',
      metadata: payload.metadata,
      createdAt: new Date(),
    };

    const adapter = this.adapters.get(payload.channel);

    if (adapter) {
      adapter
        .send(payload)
        .then((result) => {
          if (result.success) {
            notification.status = 'sent';
            notification.sentAt = new Date();
            this.eventBus.emit({
              type: 'notification:sent',
              notification,
              timestamp: new Date(),
            });
          } else {
            notification.status = 'failed';
            this.eventBus.emit({
              type: 'notification:failed',
              notification,
              error: result.error ?? 'Unknown error',
              timestamp: new Date(),
            });
          }
        })
        .catch((err: unknown) => {
          notification.status = 'failed';
          const errorMessage = err instanceof Error ? err.message : 'Unknown error';
          this.eventBus.emit({
            type: 'notification:failed',
            notification,
            error: errorMessage,
            timestamp: new Date(),
          });
        });
    } else {
      this.logger.info(
        `No adapter for channel "${payload.channel}" — notification ${notification.id} stored as pending`,
      );
    }

    this.notifications.push(notification);
    this.logger.info(`Notification dispatched: ${notification.id} to ${payload.recipient}`);
  }

  /**
   * Get all notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

