import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let preferencesRepo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    preferencesRepo = new PreferencesRepository(db);
    service = new PreferencesService(preferencesRepo);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return undefined when no preferences exist', () => {
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return preferences after they are created', () => {
      service.getOrCreatePreferences('user-1');
      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should create default preferences for a new user', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_updated',
      ]);
    });

    it('should create default SMS preferences (disabled by default)', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_updated',
      ]);
    });

    it('should create default webhook preferences (disabled by default)', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_updated',
      ]);
    });

    it('should return existing preferences without creating duplicates', () => {
      const first = service.getOrCreatePreferences('user-1');
      const second = service.getOrCreatePreferences('user-1');

      expect(first.id).toBe(second.id);
      expect(preferencesRepo.count()).toBe(1);
    });

    it('should generate sequential IDs', () => {
      const a = service.getOrCreatePreferences('user-1');
      const b = service.getOrCreatePreferences('user-2');

      expect(a.id).toBe('pref-0001');
      expect(b.id).toBe('pref-0002');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should disable email notifications', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        enabled: false,
      });

      expect(updated.email.enabled).toBe(false);
      // Other settings preserved
      expect(updated.email.frequency).toBe('immediate');
      expect(updated.email.subscribedCategories).toHaveLength(4);
    });

    it('should change email frequency', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'daily',
      });

      expect(updated.email.frequency).toBe('daily');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update subscribed categories', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });

      expect(updated.email.subscribedCategories).toEqual([
        'order_confirmation',
      ]);
    });

    it('should create preferences if none exist before updating', () => {
      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'weekly',
      });

      expect(updated.userId).toBe('user-1');
      expect(updated.email.frequency).toBe('weekly');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update multiple fields at once', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        enabled: false,
        frequency: 'weekly',
        subscribedCategories: ['welcome'],
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('weekly');
      expect(updated.email.subscribedCategories).toEqual(['welcome']);
    });
  });

  describe('updateSmsPreferences', () => {
    it('should enable SMS notifications', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateSmsPreferences('user-1', {
        enabled: true,
      });

      expect(updated.sms.enabled).toBe(true);
      expect(updated.sms.subscribedCategories).toHaveLength(4);
    });

    it('should update SMS subscribed categories', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateSmsPreferences('user-1', {
        enabled: true,
        subscribedCategories: ['order_confirmation', 'order_status_update'],
      });

      expect(updated.sms.enabled).toBe(true);
      expect(updated.sms.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
      ]);
    });

    it('should not affect email preferences when updating SMS', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', { frequency: 'daily' });
      const updated = service.updateSmsPreferences('user-1', { enabled: true });

      expect(updated.email.frequency).toBe('daily');
      expect(updated.email.enabled).toBe(true);
    });

    it('should create preferences if none exist before updating SMS', () => {
      const updated = service.updateSmsPreferences('user-1', {
        enabled: true,
      });

      expect(updated.userId).toBe('user-1');
      expect(updated.sms.enabled).toBe(true);
      // Email defaults should still be set
      expect(updated.email.enabled).toBe(true);
    });
  });

  describe('updateWebhookPreferences', () => {
    it('should enable webhook notifications', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateWebhookPreferences('user-1', {
        enabled: true,
      });

      expect(updated.webhook.enabled).toBe(true);
      expect(updated.webhook.subscribedCategories).toHaveLength(4);
    });

    it('should update webhook subscribed categories', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateWebhookPreferences('user-1', {
        enabled: true,
        subscribedCategories: ['order_confirmation'],
      });

      expect(updated.webhook.subscribedCategories).toEqual([
        'order_confirmation',
      ]);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (default behavior)', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(
        true,
      );
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.getOrCreatePreferences('user-1');
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(
        true,
      );
    });

    it('should return false when email is disabled', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(
        false,
      );
    });

    it('should return false when category is not subscribed', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['welcome'],
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(
        false,
      );
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
    });

    it('should return false for all types when email is disabled even if categories are subscribed', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(
        false,
      );
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(false);
    });
  });

  describe('shouldSend (generic multi-channel)', () => {
    it('should return false for SMS when no preferences exist (opt-in channel)', () => {
      expect(service.shouldSend('user-1', 'sms', 'order_confirmation')).toBe(false);
    });

    it('should return false for webhook when no preferences exist (opt-in channel)', () => {
      expect(service.shouldSend('user-1', 'webhook', 'order_confirmation')).toBe(false);
    });

    it('should return true for email when no preferences exist (default-allow)', () => {
      expect(service.shouldSend('user-1', 'email', 'order_confirmation')).toBe(true);
    });

    it('should return true for in_app regardless of preferences', () => {
      expect(service.shouldSend('user-1', 'in_app', 'order_confirmation')).toBe(true);
    });

    it('should return true for SMS when user has enabled SMS', () => {
      service.getOrCreatePreferences('user-1');
      service.updateSmsPreferences('user-1', { enabled: true });

      expect(service.shouldSend('user-1', 'sms', 'order_confirmation')).toBe(true);
    });

    it('should return false for SMS when user disabled SMS', () => {
      service.getOrCreatePreferences('user-1');
      // SMS is disabled by default, but explicitly disable to be clear
      service.updateSmsPreferences('user-1', { enabled: false });

      expect(service.shouldSend('user-1', 'sms', 'order_confirmation')).toBe(false);
    });

    it('should respect per-channel category subscriptions for SMS', () => {
      service.getOrCreatePreferences('user-1');
      service.updateSmsPreferences('user-1', {
        enabled: true,
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSend('user-1', 'sms', 'order_confirmation')).toBe(true);
      expect(service.shouldSend('user-1', 'sms', 'welcome')).toBe(false);
    });

    it('should allow independent channel settings', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', { enabled: false });
      service.updateSmsPreferences('user-1', { enabled: true });

      expect(service.shouldSend('user-1', 'email', 'order_confirmation')).toBe(false);
      expect(service.shouldSend('user-1', 'sms', 'order_confirmation')).toBe(true);
    });

    it('should return true for webhook when user has enabled webhook', () => {
      service.getOrCreatePreferences('user-1');
      service.updateWebhookPreferences('user-1', { enabled: true });

      expect(service.shouldSend('user-1', 'webhook', 'order_confirmation')).toBe(true);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    const preferencesRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepo);
    notificationService.setPreferencesService(preferencesService);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should send notification when user has no preferences (default allow)', async () => {
    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } satisfies OrderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress notification when user has disabled email', async () => {
    preferencesService.getOrCreatePreferences('user-1');
    preferencesService.updateEmailPreferences('user-1', { enabled: false });

    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } satisfies OrderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should suppress notification when user unsubscribed from category', async () => {
    preferencesService.getOrCreatePreferences('user-1');
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['welcome', 'account_updated'],
    });

    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } satisfies OrderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should suppress order status update when user opted out', async () => {
    preferencesService.getOrCreatePreferences('user-1');
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['order_confirmation'],
    });

    await eventBus.emit({
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    } satisfies OrderStatusChangedEvent);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should send notification when preferences service is not set', async () => {
    const plainNotificationService = new NotificationService(eventBus);

    await eventBus.emit({
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    } satisfies OrderStatusChangedEvent);

    // Both services receive the event (both subscribed to same eventBus)
    // The plain one should have processed it
    expect(plainNotificationService.getNotificationCount()).toBe(1);
  });
});

describe('NotificationService multi-channel dispatch', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    const preferencesRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepo);
    notificationService.setPreferencesService(preferencesService);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should dispatch to both email and SMS when both adapters are registered and allowed', async () => {
    const emailSent: string[] = [];
    const smsSent: string[] = [];

    notificationService.registerAdapter({
      channel: 'email',
      async send(payload) {
        emailSent.push(payload.recipient);
        return { success: true, channel: 'email' };
      },
    });
    notificationService.registerAdapter({
      channel: 'sms',
      async send(payload) {
        smsSent.push(payload.recipient);
        return { success: true, channel: 'sms' };
      },
    });

    // Enable SMS for this user
    preferencesService.getOrCreatePreferences('user-1');
    preferencesService.updateSmsPreferences('user-1', { enabled: true });

    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } satisfies OrderCreatedEvent);

    await new Promise((resolve) => setTimeout(resolve, 0));

    expect(notificationService.getNotificationCount()).toBe(2);
    expect(emailSent).toEqual(['alice@example.com']);
    expect(smsSent).toEqual(['alice@example.com']);
  });

  it('should only dispatch to email when SMS is disabled', async () => {
    const emailSent: string[] = [];
    const smsSent: string[] = [];

    notificationService.registerAdapter({
      channel: 'email',
      async send(payload) {
        emailSent.push(payload.recipient);
        return { success: true, channel: 'email' };
      },
    });
    notificationService.registerAdapter({
      channel: 'sms',
      async send(payload) {
        smsSent.push(payload.recipient);
        return { success: true, channel: 'sms' };
      },
    });

    // SMS is disabled by default — no need to explicitly disable
    preferencesService.getOrCreatePreferences('user-1');

    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } satisfies OrderCreatedEvent);

    await new Promise((resolve) => setTimeout(resolve, 0));

    expect(notificationService.getNotificationCount()).toBe(1);
    expect(emailSent).toEqual(['alice@example.com']);
    expect(smsSent).toEqual([]);
  });

  it('should dispatch to email, SMS, and webhook when all are enabled', async () => {
    const channels: string[] = [];

    notificationService.registerAdapter({
      channel: 'email',
      async send() { channels.push('email'); return { success: true, channel: 'email' }; },
    });
    notificationService.registerAdapter({
      channel: 'sms',
      async send() { channels.push('sms'); return { success: true, channel: 'sms' }; },
    });
    notificationService.registerAdapter({
      channel: 'webhook',
      async send() { channels.push('webhook'); return { success: true, channel: 'webhook' }; },
    });

    preferencesService.getOrCreatePreferences('user-1');
    preferencesService.updateSmsPreferences('user-1', { enabled: true });
    preferencesService.updateWebhookPreferences('user-1', { enabled: true });

    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } satisfies OrderCreatedEvent);

    await new Promise((resolve) => setTimeout(resolve, 0));

    expect(notificationService.getNotificationCount()).toBe(3);
    expect(channels).toContain('email');
    expect(channels).toContain('sms');
    expect(channels).toContain('webhook');
  });

  it('should respect per-channel category filtering', async () => {
    const emailSent: string[] = [];
    const smsSent: string[] = [];

    notificationService.registerAdapter({
      channel: 'email',
      async send(payload) {
        emailSent.push(payload.notificationType);
        return { success: true, channel: 'email' };
      },
    });
    notificationService.registerAdapter({
      channel: 'sms',
      async send(payload) {
        smsSent.push(payload.notificationType);
        return { success: true, channel: 'sms' };
      },
    });

    preferencesService.getOrCreatePreferences('user-1');
    // Email: only order_confirmation
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['order_confirmation'],
    });
    // SMS: enabled, only order_status_update
    preferencesService.updateSmsPreferences('user-1', {
      enabled: true,
      subscribedCategories: ['order_status_update'],
    });

    // Trigger order_confirmation — should only go to email
    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } satisfies OrderCreatedEvent);

    await new Promise((resolve) => setTimeout(resolve, 0));

    expect(emailSent).toEqual(['order_confirmation']);
    expect(smsSent).toEqual([]);

    // Trigger order_status_update — should only go to SMS
    await eventBus.emit({
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 10,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    } satisfies OrderStatusChangedEvent);

    await new Promise((resolve) => setTimeout(resolve, 0));

    expect(emailSent).toEqual(['order_confirmation']); // unchanged
    expect(smsSent).toEqual(['order_status_update']);
  });

  it('should suppress all channels when user disables all', async () => {
    const sent: string[] = [];

    notificationService.registerAdapter({
      channel: 'email',
      async send() { sent.push('email'); return { success: true, channel: 'email' }; },
    });
    notificationService.registerAdapter({
      channel: 'sms',
      async send() { sent.push('sms'); return { success: true, channel: 'sms' }; },
    });

    preferencesService.getOrCreatePreferences('user-1');
    preferencesService.updateEmailPreferences('user-1', { enabled: false });
    // SMS is already disabled by default

    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } satisfies OrderCreatedEvent);

    await new Promise((resolve) => setTimeout(resolve, 0));

    expect(notificationService.getNotificationCount()).toBe(0);
    expect(sent).toEqual([]);
  });
});

